#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

int n,m,a,b,c;
int r[1005][1005],d[4][1005][1005],v[1005][1005],ans=1e18;
int dx[]={0,0,-1,1};
int dy[]={1,-1,0,0};
struct nd{
    int x,y,dis;
    bool operator<(const nd&b)const{
        return dis>b.dis;
    }
};
void dj(int k,int sx,int sy)
{
    cl(v);
    priority_queue<nd> q;
    FOR(i,1,n)
    {
        FOR(j,1,m)
        {
            d[k][i][j]=1e18;
        }
    }
    q.push({sx,sy,r[sx][sy]});
    d[k][sx][sy]=r[sx][sy];
    wh(q.size())
    {
        int fx=q.top().x,fy=q.top().y;
        q.pop();
        if(v[fx][fy])
        {
            continue;
        }
        v[fx][fy]=1;
        FOR(i,0,3)
        {
            int nx=fx+dx[i],ny=fy+dy[i];
            if(nx<1||nx>n||ny<1||ny>m)
            {
                continue;
            }
            if(d[k][nx][ny]>d[k][fx][fy]+r[nx][ny])
            {
                d[k][nx][ny]=d[k][fx][fy]+r[nx][ny];
                q.push({nx,ny,d[k][nx][ny]});
            }
        }
    }
}
signed main(void)
{
    n=read(),m=read(),a=read(),b=read(),c=read();
    FOR(i,1,n)
    {
        FOR(j,1,m)
        {
            r[i][j]=read();
        }
    }
	dj(1,1,a);
	dj(2,n,b);
	dj(3,n,c);
    FOR(i,1,n)
    {
        FOR(j,1,m)
        {
            ans=min(ans,d[1][i][j]+d[2][i][j]+d[3][i][j]-2*r[i][j]);
        }
    }
    writeln(ans);
    return false;
}
